#include <bits/stdc++.h>
using namespace std;

vector<int> directions = {0, 1, 0, -1, 0};

void updateMatrix(vector<vector<int>>& matrix) {
    int rows = matrix.size(), cols = matrix[0].size();
    queue<pair<int, int>> to_process;
    for (int row = 0; row < rows; ++row)
        for (int col = 0; col < cols; ++col)
            if (matrix[row][col] == 0) to_process.emplace(row, col);
            else matrix[row][col] = -1;

    while (!to_process.empty()) {
        auto it = to_process.front(); 
        int row = it.first;
        int col = it.second;
        to_process.pop();
        for (int i = 0; i < 4; ++i) {
            int new_row = row + directions[i], new_col = col + directions[i+1];
            if (new_row < 0 || new_row == rows || new_col < 0 || new_col == cols || matrix[new_row][new_col] != -1) continue;
            matrix[new_row][new_col] = matrix[row][col] + 1;
            to_process.emplace(new_row, new_col);
        }
    }
}

int main() {


  int n, m;
  cin >> n >> m;

  assert(1 <= n && n <= 100);
  assert(1 <= m && m <= 100);

  vector<vector<int> > mat(n, vector<int> (m));
  for(int i = 0; i < n; i++){
    for(int j = 0; j < m; j++){
