#include <stdio.h>
#include <stdbool.h>
#include <stdlib.h>
#include <assert.h>

int directions[] = {0, 1, 0, -1, 0};

void updateMatrix(int matrix[][100], int numRows, int numCols) {
    int rows = numRows, cols = numCols;
    int queue[rows * cols][2];
    int front = 0, rear = 0;

    for (int row = 0; row < rows; ++row) {
        for (int col = 0; col < cols; ++col) {
            if (matrix[row][col] == 0) {
                queue[rear][0] = row;
                queue[rear++][1] = col;
            } else {
                matrix[row][col] = -1;
            }
        }
    }

    while (front != rear) {
        int row = queue[front][0];
        int col = queue[front][1];
        front++;

        for (int i = 0; i < 4; ++i) {
            int new_row = row + directions[i], new_col = col + directions[i+1];
            if (new_row < 0 || new_row == rows || new_col < 0 || new_col == cols || matrix[new_row][new_col] != -1) continue;
            matrix[new_row][new_col] = matrix[row][col] + 1;
            queue[rear][0] = new_row;
            queue[rear++][1] = new_col;
        }
    }
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);

    assert(1 <= n && n <= 100);
    assert(1 <= m && m <= 100);

