function updateMatrix(matrix) {
    const rows = matrix.length;
    const cols = matrix[0].length;
    const directions = [0, 1, 0, -1, 0];
    const toProcess = [];

    for (let row = 0; row < rows; row++) {
        for (let col = 0; col < cols; col++) {
            if (matrix[row][col] === 0) {
                toProcess.push([row, col]);
            } else {
                matrix[row][col] = -1;
            }
        }
    }
    while (toProcess.length > 0) {
        const [row, col] = toProcess.shift();
        for (let i = 0; i < 4; i++) {
            const newRow = row + directions[i];
            const newCol = col + directions[i + 1];
            if (newRow >= 0 && newRow < rows && newCol >= 0 && newCol < cols && matrix[newRow][newCol] === -1) {
                matrix[newRow][newCol] = matrix[row][col] + 1;
                toProcess.push([newRow, newCol]);
            }
        }
    }
}

